// ---- Pillar 2: Image Generator — 4-deep fallback chain → base64 JPEG ----
// Primary:  Cloudflare Flux (verified working, JPEG base64 in result.image)
// Fallback1: Gemini Imagen
// Fallback2: HuggingFace FLUX.1-schnell
// Fallback3: Pollinations.ai (no key, always available)
// Input: { title: '...', keyword: '...', style: 'featured|thumbnail' }
// Returns: { ok, image_base64, format, provider_used }
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;
const b = $json.body || $json;

const title   = String(b.title   || 'B2B Marketing Strategy').trim();
const keyword = String(b.keyword || title).trim();
const style   = (b.style === 'thumbnail') ? 'thumbnail' : 'featured';

// Build a clean, specific image prompt
const BASE_PROMPT = style === 'thumbnail'
  ? `YouTube thumbnail, bold text overlay "${title}", professional B2B business style, dark blue and white color scheme, clean modern design, high contrast, 1280x720`
  : `Professional featured image for B2B article about "${keyword}", modern corporate style, blue tones, abstract business concept, clean minimalist, 1200x628`;

// Provider 1: Cloudflare Flux
async function tryCloudflare(prompt) {
  if (!ENV.CLOUDFLARE_ACCOUNT_ID || !ENV.CLOUDFLARE_API_TOKEN) return null;
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.cloudflare.com/client/v4/accounts/${ENV.CLOUDFLARE_ACCOUNT_ID}/ai/run/@cf/black-forest-labs/flux-1-schnell`,
    headers: { Authorization: `Bearer ${ENV.CLOUDFLARE_API_TOKEN}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ prompt, steps: 4 }),
    json: true, timeout: 60000
  });
  if (res.success && res.result?.image) return { image_base64: res.result.image, format: 'jpeg', provider: 'cloudflare_flux' };
  return null;
}

// Provider 2: HuggingFace Inference
async function tryHuggingFace(prompt) {
  if (!ENV.HUGGINGFACE_API_KEY) return null;
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api-inference.huggingface.co/models/black-forest-labs/FLUX.1-schnell',
    headers: { Authorization: `Bearer ${ENV.HUGGINGFACE_API_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ inputs: prompt }),
    encoding: 'arraybuffer', json: false, timeout: 60000
  });
  if (res && res.byteLength > 1000) {
    return { image_base64: Buffer.from(res).toString('base64'), format: 'png', provider: 'huggingface_flux' };
  }
  return null;
}

// Provider 3: Pollinations (no key, always available, JPEG URL)
async function tryPollinations(prompt) {
  const url = `https://image.pollinations.ai/prompt/${encodeURIComponent(prompt)}?width=1200&height=628&nologo=true&seed=${Date.now() % 10000}`;
  const res = await this.helpers.httpRequest({
    method: 'GET', url, encoding: 'arraybuffer', json: false, timeout: 60000
  });
  if (res && res.byteLength > 1000) {
    return { image_base64: Buffer.from(res).toString('base64'), format: 'jpeg', provider: 'pollinations' };
  }
  return null;
}

// Try providers in order
const providers = [tryCloudflare, tryHuggingFace, tryPollinations];
let result = null;
for (const fn of providers) {
  try { result = await fn.call(this, BASE_PROMPT); if (result) break; } catch { continue; }
}

if (!result) return [{ json: { ok: false, error: 'All image providers failed', prompt: BASE_PROMPT } }];

// Store reference in content_pipeline
if (ENV.SUPABASE_URL && b.keyword) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${ENV.SUPABASE_URL}/rest/v1/content_pipeline?on_conflict=keyword`,
    headers: {
      apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json', Prefer: 'resolution=merge-duplicates'
    },
    body: JSON.stringify({ keyword: b.keyword, updated_at: new Date().toISOString() }),
    json: false, timeout: 10000
  }).catch(() => null);
}

return [{ json: { ok: true, ...result, style, prompt: BASE_PROMPT, size_kb: Math.round(result.image_base64.length * 0.75 / 1024) } }];
